package com.securestack.analysis.ai;import java.util.*;import org.springframework.stereotype.Component;import com.securestack.model.Enums.*;public class Ai{public record AiAnalysisRequest(String scanName,int riskScore,Map<Severity,Long> severityCounts,Map<Category,Long> categoryCounts,String reviewDepth){} public record AiAnalysisResult(String executiveSummary,List<String> topRisks,String remediationPlan,String limitations,String suggestedNextSteps){} public interface AiAnalysisProvider{AiAnalysisResult generateSummary(AiAnalysisRequest request);} @Component public static class MockAiAnalysisProvider implements AiAnalysisProvider{public AiAnalysisResult generateSummary(AiAnalysisRequest r){long c=r.severityCounts.getOrDefault(Severity.CRITICAL,0L),h=r.severityCounts.getOrDefault(Severity.HIGH,0L);String posture=c>0?"critical":h>0?"elevated":r.riskScore<90?"moderate":"low";return new AiAnalysisResult("SecureStack AI found a "+posture+" risk posture for '"+r.scanName+"'. The score is "+r.riskScore+"/100 based on detected static security signals. Prioritize confirmed evidence and perform manual review before production decisions.",List.of("Address critical and high findings first","Rotate any exposed credentials","Tighten cloud, API, and container configuration"),"1. Rotate secrets. 2. Restrict public access and broad permissions. 3. Add authentication, validation, logging redaction, and rate limiting. 4. Re-run the scan and verify fixes.","Automated review is not a complete security audit and does not execute code or prove exploitability.","Add CI secret scanning, dependency scanning, and manual threat modeling for sensitive systems.");}}}
